# CMT 부여: A8 정책에 따른 구획 번호 매핑
if meta['a8_state'] == 'SINGLE-DRUG':
    df['CMT'] = np.where(df['EVID'].isin([1,3,4]), 1, 2)
else:
    df['CMT'] = df['analyte_label'].map(cmt_map)
assert (df.loc[df['EVID'].isin([0,1,3,4]), 'CMT'] > 0).all()

