# BLQ_FLAG 부여: BLQ → 1, non-BLQ → 0 (M3/M4 policy)
if (meta$blq_policy %in% c('M3', 'M4')) {
  df$BLQ_FLAG <- ifelse(df$blq_detected, 1L, 0L)
}  # M1/M5: BLQ_FLAG 컬럼 미생성

# LLOQ 부여: BLQ_FLAG 존재 시 LLOQ>0 필수
if ('BLQ_FLAG' %in% names(df)) {
  df$LLOQ <- df$lloq_value
  stopifnot(all(df$LLOQ[df$EVID == 0] > 0))
  stopifnot(all(df$LLOQ[df$BLQ_FLAG == 1] > 0))
}

