# I-R01~I-R15 행 수준 불변 조건 검증
violations = []
if not (df['ID'] > 0).all(): violations.append('I-R01')
if not df['TIME'].notna().all(): violations.append('I-R02')
if not df['EVID'].isin([0,1,2,3,4]).all(): violations.append('I-R03')
if not df['MDV'].isin([0,1]).all(): violations.append('I-R04')
assert len(violations) == 0, f'Invariant violations: {violations}'

